mapper.select:
SELECT * FROM (
    SELECT t.*, ROWNUM rn FROM (
        SELECT * FROM SHOP

            AND SHOP_NAME LIKE '%' || #{shopName} || '%'
            AND BUILDING = #{building}
            AND BUSINESS_TYPE = #{businessType}
            AND STATUS = #{status}

        ORDER BY CREATE_TIME DESC
    ) t WHERE ROWNUM <= #{offset} + #{limit}
) WHERE rn > #{offset}

SELECT COUNT(*) FROM SHOP

    AND SHOP_NAME LIKE '%' || #{shopName} || '%'
    AND BUILDING = #{building}
    AND BUSINESS_TYPE = #{businessType}
    AND STATUS = #{status}

mapper.update:
UPDATE SHOP SET
    SHOP_NO = #{shopNo}, SHOP_NAME = #{shopName}, BUILDING = #{building}, FLOOR_NO = #{floorNo},
    BUSINESS_TYPE = #{businessType}, CONTACT_PERSON = #{contactPerson}, CONTACT_PHONE = #{contactPhone},
    STATUS = #{status}
WHERE SHOP_ID = #{shopId}
